correct_approach.code:
-- Correct way to access query parameters
DECLARE location CHARACTER;
SET location = InputLocalEnvironment.HTTP.Input.QueryString.location;

-- For query string: ?location=London&country=UK
DECLARE location CHARACTER;
DECLARE country CHARACTER;
SET location = InputLocalEnvironment.HTTP.Input.QueryString.location;  -- Gets "London"
SET country = InputLocalEnvironment.HTTP.Input.QueryString.country;    -- Gets "UK"

pattern.example:
BROKER SCHEMA com.weather.api

CREATE COMPUTE MODULE ValidateInput
  CREATE FUNCTION Main() RETURNS BOOLEAN
  BEGIN
    -- Extract query parameters from InputLocalEnvironment
    -- NOTE: HTTP Input node must have parseQueryString="true" configured
    DECLARE location CHARACTER;
    SET location = InputLocalEnvironment.HTTP.Input.QueryString.location;

    -- Validate that required parameter is provided
    IF location IS NULL OR LENGTH(TRIM(location)) = 0 THEN
      -- Build error response
      CREATE FIELD OutputRoot.JSON.Data;
      SET OutputRoot.JSON.Data.error = 'Location parameter is required';
      SET OutputRoot.JSON.Data.message = 'Please provide a location parameter in the query string';

      -- Set HTTP response code to 400 Bad Request
      SET OutputLocalEnvironment.Destination.HTTP.ReplyStatusCode = 400;

      -- Propagate to failure terminal
      PROPAGATE TO TERMINAL 'failure';
      RETURN FALSE;
    END IF;

    -- Store validated parameter in Environment for downstream use
    SET Environment.Variables.location = location;

    RETURN TRUE;
  END;
END MODULE;

CREATE COMPUTE MODULE ExtractQueryParams
  CREATE FUNCTION Main() RETURNS BOOLEAN
  BEGIN
    -- Extract multiple query parameters from InputLocalEnvironment
    -- NOTE: HTTP Input node must have parseQueryString="true" configured
    DECLARE location CHARACTER;
    DECLARE units CHARACTER;
    DECLARE lang CHARACTER;

    SET location = InputLocalEnvironment.HTTP.Input.QueryString.location;
    SET units = InputLocalEnvironment.HTTP.Input.QueryString.units;
    SET lang = InputLocalEnvironment.HTTP.Input.QueryString.lang;

    -- Provide defaults for optional parameters
    IF units IS NULL OR units = '' THEN
      SET units = 'metric';
    END IF;

    IF lang IS NULL OR lang = '' THEN
      SET lang = 'en';
    END IF;

    -- Store in Environment
    SET Environment.Variables.location = location;
    SET Environment.Variables.units = units;
    SET Environment.Variables.lang = lang;

    RETURN TRUE;
  END;
END MODULE;

-- Query string: ?location=New%20York
DECLARE location CHARACTER;
SET location = InputLocalEnvironment.HTTP.Input.QueryString.location;
-- location will contain "New York" (already decoded)

